public static void allowEditFieldGroup(FormDataSource _formDataSource, FieldGroupName _fieldGroupName)
{
    DictTable   dictTable       = new DictTable(_formDataSource.table());
    Set         allowEditFields = getFieldGroupFields(_formDataSource.table(), _fieldGroupName);

    _formDataSource.allowEdit(true);

    for(int i = 1; i <= dictTable.fieldCnt(); i++)
    {
        var fieldId = dictTable.fieldCnt2Id(i);

        if (!isSysId(fieldId)) //Exclude system fields
        {
            FormDataObject  formDataObject = _formDataSource.object(fieldId);

            if (formDataObject)
            {
                formDataObject.allowEdit(allowEditFields.in(fieldId));
            }
        }
    }
}

public static Set getFieldGroupFields(TableId _tableId, FieldGroupName _fieldGroupName)
{
    Set             fields         = new Set(Types::Integer);
    DictFieldGroup  dictFieldGroup = new DictFieldGroup(_tableId, _fieldGroupName);

    if (dictFieldGroup)
    {
        for (int i = 1; i <= dictFieldGroup.numberOfFields(); i++)
        {
            fields.add(dictFieldGroup.field(i));
        }
    }

    return fields;
}

/// <summary>
/// Returns <c>true</c> if the Current Company was a Spanish Company.
/// </summary>
/// <returns>boolean</returns>
/// <remarks>Extension needed in ETGSPAIN model</remarks>
public static boolean CurrentCompanyIsSpanishCompany()
{
    return (CompanyInfo::findDataArea(curExt()).ETGSpanishCompany == NoYes::Yes ? true : false);
}
